    /// <summary>The raw node of whichever <c>pattern*</c> variant is present, or null.</summary>
    [JsonIgnore]
    public JsonNode? Pattern
    {
        get
        {
            foreach (var key in PatternVariantKeys)
            {
                if (MutableNode[key] is JsonNode node)
                {
                    return node;
                }
            }

            return null;
        }
    }

    private void SetPatternVariant(string key, JsonNode? value)
    {
        foreach (var variant in PatternVariantKeys)
        {
            if (variant != key)
            {
                MutableNode.Remove(variant);
            }
        }

        if (value is null)
        {
            MutableNode.Remove(key);
        }
        else
        {
            // A JsonNode can have only one parent; clone if it is already attached elsewhere.
            MutableNode[key] = value.Parent is null ? value : value.DeepClone();
        }
    }

